const SRC=$('Config').first().json.srcUrl;
const fedId=(($('Webhook').first().json.body)||{}).id||'s2dfts98qyvmew2';
let html='';
try{html=await this.helpers.httpRequest({method:'GET',url:SRC,headers:{'User-Agent':'Mozilla/5.0'}});}catch(e){return [{json:{error:'fetch:'+e.message}}];}
html=String(html);
const cfdecode=(hx)=>{try{const b=hx.match(/../g).map(x=>parseInt(x,16));const k=b[0];return b.slice(1).map(c=>String.fromCharCode(c^k)).join('');}catch(e){return '';}};
const strip=(s)=>s.replace(/<[^>]+>/g,'').replace(/&amp;/g,'&').replace(/&#0?38;/g,'&').replace(/&nbsp;/g,' ').trim();
const rows=html.match(/<tr[^>]*>[\s\S]*?<\/tr>/g)||[];
const out=[];
for(const r of rows){const tds=r.match(/<td[^>]*>[\s\S]*?<\/td>/g)||[];if(tds.length<4)continue;
  const name=strip(tds[0]);if(!name||name.toLowerCase()==='klubb')continue;
  const city=strip(tds[1]);
  const cf=(tds[2].match(/data-cfemail="([0-9a-f]+)"/)||[])[1];
  const email=(cf?cfdecode(cf):strip(tds[2])).toLowerCase().trim();
  const wm=(tds[3].match(/href="(https?:\/\/[^"]+)"/)||[])[1]||strip(tds[3]);
  out.push({name,city,email,web:wm||'',fedId});
}
return out.map(o=>({json:o}));

const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,'');
const SRC=$('Config').first().json.srcUrl;
const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
const isEmail=(e)=>/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(e);
const isSocial=(u)=>/facebook|instagram|twitter|x\.com|tiktok|youtube|linkedin/i.test(u);
const normUrl=(u)=>{u=String(u||'').trim();if(!u)return '';if(u.startsWith('//'))u='https:'+u;if(!/^https?:/i.test(u))u='https://'+u;return u;};
const uslug=(s)=>String(s||'').toLowerCase().trim().replace(/[^\p{L}\p{N}]+/gu,'-').replace(/^-+|-+$/g,'');
const now=new Date().toISOString();
const findClub=async(k)=>{const r=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/clubs/records',qs:{filter:"(dedup_key='"+k+"')",perPage:1},headers:pbH,json:true});return (r.items&&r.items[0])||null;};
const findContact=async(e)=>{const r=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/contacts/records',qs:{filter:"(email='"+e.replace(/'/g,'')+"')",perPage:1},headers:pbH,json:true});return (r.items&&r.items[0])||null;};
let created=0,contactsC=0;
for(const it of $input.all()){const c=it.json; const name=String(c.name||'').trim(); if(!name)continue;
  let site=normUrl(c.web||''); if(isSocial(site))site='';
  const email=String(c.email||'').toLowerCase().trim();
  const dedup='NOR:'+uslug(name);
  const base={federation:c.fedId,name,country:'Norway',city:c.city||'',dedup_key:dedup,source_url:SRC,last_scraped:now};
  let clubId=null;
  try{ try{const rec=await this.helpers.httpRequest({method:'POST',url:PB_URL+'/api/collections/clubs/records',headers:pbH,body:Object.assign({},base,{website_url:site,website_source:site?'official_list':'none',status:'new'}),json:true});created++;clubId=rec.id;}
    catch(e){const ex=await findClub(dedup);if(ex){const p=Object.assign({},base);if(site){p.website_url=site;p.website_source='official_list';}await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/clubs/records/'+ex.id,headers:pbH,body:p,json:true});clubId=ex.id;}else throw e;} }
  catch(e){continue;}
  if(email&&isEmail(email)){ try{await this.helpers.httpRequest({method:'POST',url:PB_URL+'/api/collections/contacts/records',headers:pbH,body:{club:clubId,email,source_url:SRC,source_type:'directory',verification_status:'unverified'},json:true});contactsC++;}
    catch(e){try{const ex=await findContact(email);if(ex&&!ex.club)await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/contacts/records/'+ex.id,headers:pbH,body:{club:clubId},json:true});}catch(_){}}
  }
}
return [{json:{batch:$input.all().length,created,contactsC}}];

const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,'');
const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
const fedId=(($('Webhook').first().json.body)||{}).id||'s2dfts98qyvmew2';
const r=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/clubs/records',qs:{filter:'federation="'+fedId+'"',perPage:1},headers:pbH,json:true});
const n=r.totalItems||0;
await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/federations/records/'+fedId,headers:pbH,body:{status:(n>0?'scraped':'needs_review'),club_count:n,last_scraped:new Date().toISOString()},json:true});
return [{json:{ok:true,clubs:n}}];
